export function parse(raw) {
  if (raw === 'true' || raw === 'false') return { kind: 'bool', value: raw === 'true' };
  if (/^\d+$/.test(raw)) return { kind: 'num', value: Number(raw) };
  return { kind: 'str', value: raw };
}

export function print(node) {
  if (node.kind === 'num') return 'num:' + node.value;
  if (node.kind === 'str') return 'str:' + node.value;
  if (node.kind === 'bool') return 'bool:' + node.value;
  throw new Error('unknown kind ' + node.kind);
}
